import{_ as t,a,b as r,c as n,d as i}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as o,o as s,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const D=JSON.parse('{"title":"Ajouter un canal OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/upload/onedrive.md","filePath":"fr-FR/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"fr-FR/upload/onedrive.md"};function p(h,e,u,m,b,f){return s(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="ajouter-un-canal-onedrive" tabindex="-1">Ajouter un canal OneDrive <a class="header-anchor" href="#ajouter-un-canal-onedrive" aria-label="Permalink to &quot;Ajouter un canal OneDrive&quot;">​</a></h1><p>Le canal OneDrive utilise Microsoft OneDrive comme destination de stockage.</p><h2 id="a-preparer" tabindex="-1">À préparer <a class="header-anchor" href="#a-preparer" aria-label="Permalink to &quot;À préparer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Élément</th><th>Utilité</th></tr></thead><tbody><tr><td>Compte Microsoft</td><td>Gérer OneDrive et l’enregistrement de l’application</td></tr><tr><td>Domaine ImgBed</td><td>Configurer le callback OAuth</td></tr><tr><td>App registration</td><td>Obtenir Client ID et Client Secret</td></tr><tr><td>Refresh Token</td><td>Maintenir l’accès dans le temps</td></tr></tbody></table><h2 id="ouvrir-microsoft-entra-id" tabindex="-1">Ouvrir Microsoft Entra ID <a class="header-anchor" href="#ouvrir-microsoft-entra-id" aria-label="Permalink to &quot;Ouvrir Microsoft Entra ID&quot;">​</a></h2><ol><li>Ouvrez <code>portal.azure.com</code>.</li><li>Recherchez <code>Microsoft Entra ID</code>.</li><li>Entrez dans <code>App registrations</code>.</li><li>Cliquez sur <code>New registration</code>.</li></ol><h2 id="enregistrer-l-application" tabindex="-1">Enregistrer l’application <a class="header-anchor" href="#enregistrer-l-application" aria-label="Permalink to &quot;Enregistrer l’application&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Name</td><td>Par exemple <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Selon le type de OneDrive utilisé</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://votre-domaine/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Pour un OneDrive personnel, choisissez les comptes Microsoft personnels. Pour accepter comptes personnels et professionnels, choisissez l’option compatible avec les deux.</p><p><img src="'+t+'" alt="Enregistrement OneDrive" loading="lazy"></p><p>Après l’enregistrement, copiez <code>Application (client) ID</code>. Pour un compte professionnel, conservez aussi <code>Directory (tenant) ID</code>.</p><p><img src="'+a+'" alt="Application ID et Tenant ID" loading="lazy"></p><h2 id="creer-le-client-secret" tabindex="-1">Créer le Client Secret <a class="header-anchor" href="#creer-le-client-secret" aria-label="Permalink to &quot;Créer le Client Secret&quot;">​</a></h2><ol><li>Ouvrez <code>Certificates &amp; secrets</code>.</li><li>Cliquez sur <code>New client secret</code>.</li><li>Définissez le nom et l’expiration.</li><li>Copiez immédiatement la valeur <code>Value</code>.</li></ol><p><img src="'+r+'" alt="Client Secret" loading="lazy"></p><p>Cette valeur peut ne plus être affichée ensuite. Enregistrez-la dès sa création.</p><h2 id="permissions-microsoft-graph" tabindex="-1">Permissions Microsoft Graph <a class="header-anchor" href="#permissions-microsoft-graph" aria-label="Permalink to &quot;Permissions Microsoft Graph&quot;">​</a></h2><p>Dans <code>API permissions</code>, ajoutez des delegated permissions Microsoft Graph.</p><table tabindex="0"><thead><tr><th>Permission</th><th>Utilité</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Envoyer, créer des dossiers et supprimer des fichiers</td></tr><tr><td><code>offline_access</code></td><td>Obtenir un Refresh Token</td></tr><tr><td><code>User.Read</code></td><td>Lire les informations du compte et la capacité</td></tr></tbody></table><h2 id="renseigner-dans-imgbed" tabindex="-1">Renseigner dans ImgBed <a class="header-anchor" href="#renseigner-dans-imgbed" aria-label="Permalink to &quot;Renseigner dans ImgBed&quot;">​</a></h2><p>Dans Paramètres d’upload, choisissez <code>OneDrive</code>.</p><table tabindex="0"><thead><tr><th>Champ</th><th>Valeur</th></tr></thead><tbody><tr><td>Nom du canal</td><td>Par exemple <code>OneDrive Main</code></td></tr><tr><td>Client ID</td><td><code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>Valeur du Client Secret</td></tr><tr><td>Tenant ID</td><td>Voir le tableau ci-dessous</td></tr><tr><td>Refresh Token</td><td>Laissez vide au début</td></tr><tr><td>Dossier racine</td><td>Optionnel, souvent <code>imgbed</code></td></tr></tbody></table><p><img src="'+n+'" alt="Configuration OneDrive" loading="lazy"></p><table tabindex="0"><thead><tr><th>Type de compte</th><th>Tenant ID</th></tr></thead><tbody><tr><td>Compte personnel</td><td><code>consumers</code></td></tr><tr><td>Personnel + professionnel</td><td><code>common</code></td></tr><tr><td>Organisation actuelle uniquement</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h2 id="obtenir-le-refresh-token" tabindex="-1">Obtenir le Refresh Token <a class="header-anchor" href="#obtenir-le-refresh-token" aria-label="Permalink to &quot;Obtenir le Refresh Token&quot;">​</a></h2><ol><li>Dans ImgBed, cliquez sur <code>Obtenir le token</code>.</li><li>Connectez-vous avec le compte Microsoft de destination.</li><li>Acceptez les permissions.</li><li>Copiez le <code>Refresh Token</code> affiché sur la page de callback.</li><li>Revenez dans ImgBed et collez-le dans le champ correspondant.</li></ol><p><img src="'+i+`" alt="Refresh Token" loading="lazy"></p><h2 id="flux-rapide" tabindex="-1">Flux rapide <a class="header-anchor" href="#flux-rapide" aria-label="Permalink to &quot;Flux rapide&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ouvrir portal.azure.com</span></span>
<span class="line"><span>-&gt; Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; App registrations</span></span>
<span class="line"><span>-&gt; New registration</span></span>
<span class="line"><span>-&gt; Configurer le callback Web</span></span>
<span class="line"><span>-&gt; Copier Application ID</span></span>
<span class="line"><span>-&gt; Créer Client Secret</span></span>
<span class="line"><span>-&gt; Ajouter les permissions Microsoft Graph</span></span>
<span class="line"><span>-&gt; Renseigner Client ID / Secret / Tenant ID dans ImgBed</span></span>
<span class="line"><span>-&gt; Obtenir le token</span></span>
<span class="line"><span>-&gt; Coller le Refresh Token et enregistrer</span></span></code></pre></div>`,29)])])}const C=o(c,[["render",p]]);export{D as __pageData,C as default};
